// ═══════════════════════════════════════════════════════════════
// HELPERS — Fonctions utilitaires
// ═══════════════════════════════════════════════════════════════

// Convertit un rating en rareté
function getRarityFromRating(rating) {
  if (rating >= 89) return 'legende';
  if (rating >= 84) return 'diamant';
  if (rating >= 78) return 'or';
  if (rating >= 70) return 'argent';
  return 'bronze';
}

// Récupère tous les joueurs d'une équipe
function getPlayersByTeam(equipe) {
  return ALL_PLAYERS.filter(p => p.equipe === equipe);
}

// Récupère tous les joueurs d'une rareté donnée
function getPlayersByRarity(rarity) {
  return ALL_PLAYERS.filter(p => getRarityFromRating(p.base_rating) === rarity);
}

// Statistiques globales
function getPlayerStats() {
  const stats = { bronze: 0, argent: 0, or: 0, diamant: 0, legende: 0 };
  ALL_PLAYERS.forEach(p => {
    stats[getRarityFromRating(p.base_rating)]++;
  });
  return stats;
}

